WHEN NOT MATCHED BY TARGET THEN
    INSERT (CalendarDate, QuarterName, MonthNumber, MonthName, MonthShortName, WeekOfYear, WeekOfMonth, DayOfYear, DayOfMonth, DayName, DayShortName, DaysInMonth, CalendarDateTime, CalendarYear, DayNumberOfWeek)
