) AS source (CalendarDate, QuarterName, MonthNumber, MonthName, MonthShortName, WeekOfYear, WeekOfMonth, DayOfYear, DayOfMonth, DayName, DayShortName, DaysInMonth, CalendarDateTime, CalendarYear, DayNumberOfWeek)
ON target.CalendarDate = source.CalendarDate
WHEN MATCHED THEN
    UPDATE SET
        QuarterName = source.QuarterName,
        MonthNumber = source.MonthNumber,
        MonthName = source.MonthName,
        MonthShortName = source.MonthShortName,
        WeekOfYear = source.WeekOfYear,
        WeekOfMonth = source.WeekOfMonth,
        DayOfYear = source.DayOfYear,
        DayOfMonth = source.DayOfMonth,
        DayName = source.DayName,
        DayShortName = source.DayShortName,
        DaysInMonth = source.DaysInMonth,
        CalendarDateTime = source.CalendarDateTime,
        CalendarYear = source.CalendarYear,
        DayNumberOfWeek = source.DayNumberOfWeek
WHEN NOT MATCHED BY TARGET THEN
    INSERT (CalendarDate, QuarterName, MonthNumber, MonthName, MonthShortName, WeekOfYear, WeekOfMonth, DayOfYear, DayOfMonth, DayName, DayShortName, DaysInMonth, CalendarDateTime, CalendarYear, DayNumberOfWeek)
    VALUES (source.CalendarDate, source.QuarterName, source.MonthNumber, source.MonthName, source.MonthShortName, source.WeekOfYear, source.WeekOfMonth, source.DayOfYear, source.DayOfMonth, source.DayName, source.DayShortName, source.DaysInMonth, source.CalendarDateTime, source.CalendarYear, source.DayNumberOfWeek);

COMMIT;

SELECT COUNT(*) AS CalendarRows, MIN(CalendarDate) AS MinDate, MAX(CalendarDate) AS MaxDate FROM dbo.Calendar;
